import scala.collection.mutable.PriorityQueue

def solve(m: Long, n: Long, waitCost: Array[Array[Long]]): Long = {
  val rows = m.toInt
  val cols = n.toInt
  val dist = Array.ofDim[Long](rows, cols, 2)
  for (i <- 0 until rows) {
    for (j <- 0 until cols) {
      dist(i)(j)(0) = Long.MaxValue
      dist(i)(j)(1) = Long.MaxValue
    }
  }
  val startCost = (0 + 1) * (0 + 1)
  dist(0)(0)(1) = startCost
  val pq = PriorityQueue[(Long, Int, Int, Int)](
    (startCost, 0, 0, 1)
  )
  while (pq.nonEmpty) {
    val (currentCost, i, j, parity) = pq.dequeue
    if (i == rows - 1 && j == cols - 1) return currentCost
    if (currentCost > dist(i)(j)(parity)) continue
    if (parity == 1) {
      if (j + 1 < cols) {
        val newI = i
        val newJ = j + 1
        val newCost = currentCost + (newI + 1) * (newJ + 1)
        if (newCost < dist(newI)(newJ)(0)) {
          dist(newI)(newJ)(0) = newCost
          pq.enqueue((newCost, newI, newJ, 0))
        }
      }
      if (i + 1 < rows) {
        val newI = i + 1
        val newJ = j
        val newCost = currentCost + (newI + 1) * (newJ + 1)
        if (newCost < dist(newI)(newJ)(0)) {
          dist(newI)(newJ)(0) = newCost
          pq.enqueue((newCost, newI, newJ, 0))
        }
      }
    } else {
      val newCost = currentCost + waitCost(i)(j)
      if (newCost < dist(i)(j)(1)) {
        dist(i)(j)(1) = newCost
        pq.enqueue((newCost, i, j, 1))
      }
    }
  }
  Long.MaxValue
}
